import{_ as a,c as r,o as i,ah as t,ai as s}from"./chunks/framework.Cnj7lwEt.js";const g=JSON.parse('{"title":"91GIT - GitHub China Relay","description":"","frontmatter":{},"headers":[],"relativePath":"en/91git.md","filePath":"en/91git.md"}'),o={name:"en/91git.md"};function l(n,e,c,h,d,u){return i(),r("div",null,e[0]||(e[0]=[t('<h1 id="_91git-github-china-relay" tabindex="-1">91GIT - GitHub China Relay <a class="header-anchor" href="#_91git-github-china-relay" aria-label="Permalink to “91GIT - GitHub China Relay”">​</a></h1><p><strong>Access URL:</strong> <a href="https://91git.com/" target="_blank" rel="noreferrer">https://91git.com/</a></p><h2 id="_01-1-project-introduction" tabindex="-1">01.1- Project Introduction <a class="header-anchor" href="#_01-1-project-introduction" aria-label="Permalink to “01.1- Project Introduction”">​</a></h2><p>GitHub China Relay —— One-click search for GitHub repositories, automatic packaging of source code and Release assets, generating compressed packages for download.</p><p>Designed specifically for domestic network environments, helping developers quickly access GitHub project resources.</p><p><img src="'+s+'" alt="alt text"></p><h2 id="_01-2-features" tabindex="-1">01.2- Features <a class="header-anchor" href="#_01-2-features" aria-label="Permalink to “01.2- Features”">​</a></h2><ul><li>🔍 <strong>Keyword Search</strong> - Search GitHub repositories by keyword, sorted by Star count</li><li>📥 <strong>One-click Packaging</strong> - Automatically download source code + Release assets, generate double-encrypted compressed packages</li><li>🔥 <strong>GitHub Trending</strong> - Display top 10 newly created high-Star repositories of the week</li><li>📊 <strong>Site Hot Packages</strong> - Show most packaged repositories of the day/month</li><li>⏱️ <strong>Auto Cleanup</strong> - Packaged files auto-delete after 3 minutes if not downloaded, saving server space</li></ul><h2 id="_01-3-tech-stack" tabindex="-1">01.3- Tech Stack <a class="header-anchor" href="#_01-3-tech-stack" aria-label="Permalink to “01.3- Tech Stack”">​</a></h2><ul><li><strong>Frontend</strong>: React + TypeScript + Vite + Tailwind CSS</li><li><strong>Animation</strong>: Framer Motion</li><li><strong>Backend</strong>: Node.js + Express</li><li><strong>Packaging</strong>: archiver (ZIP)</li><li><strong>Encryption</strong>: AES-256 + ZIP Password</li></ul><h2 id="_01-4-use-cases" tabindex="-1">01.4- Use Cases <a class="header-anchor" href="#_01-4-use-cases" aria-label="Permalink to “01.4- Use Cases”">​</a></h2><h3 id="for-developers" tabindex="-1">For Developers <a class="header-anchor" href="#for-developers" aria-label="Permalink to “For Developers”">​</a></h3><ul><li>Quickly obtain GitHub project source code</li><li>Download complete Release assets</li><li>Package and share project resources</li></ul><h3 id="for-researchers" tabindex="-1">For Researchers <a class="header-anchor" href="#for-researchers" aria-label="Permalink to “For Researchers”">​</a></h3><ul><li>Batch download research tools</li><li>Archive open source projects</li><li>Build local resource libraries</li></ul><h3 id="for-enterprise-users" tabindex="-1">For Enterprise Users <a class="header-anchor" href="#for-enterprise-users" aria-label="Permalink to “For Enterprise Users”">​</a></h3><ul><li>Internal sharing of development tools</li><li>Team resource synchronization</li><li>Offline environment deployment</li></ul><h2 id="_01-5-security" tabindex="-1">01.5- Security <a class="header-anchor" href="#_01-5-security" aria-label="Permalink to “01.5- Security”">​</a></h2><ul><li>✅ Double encryption protection</li><li>✅ Automatic file cleanup</li><li>✅ No user data collection</li><li>✅ Secure transmission protocol</li></ul><h2 id="_01-6-feedback" tabindex="-1">01.6- Feedback <a class="header-anchor" href="#_01-6-feedback" aria-label="Permalink to “01.6- Feedback”">​</a></h2><p>If you have any questions or suggestions, please contact us through:</p><ul><li>GitHub Issues</li><li>Email Feedback</li><li>Online Customer Service</li></ul><hr><p><strong>Disclaimer</strong>: This tool is for learning and research purposes only. Please comply with GitHub&#39;s Terms of Service and relevant laws and regulations.</p>',24)]))}const f=a(o,[["render",l]]);export{g as __pageData,f as default};
